#!/usr/bin/env python3
"""Update all brand data files with fresh funnel metrics. Mar 30, 2026."""
import json, os
from datetime import datetime

DIR = os.path.dirname(os.path.abspath(__file__))
DATA = os.path.join(DIR, "data")

def parse_date(s):
    return datetime.strptime(s[:10], "%Y-%m-%d")

def aggregate_periods(daily_rows):
    periods = {
        "yesterday": (datetime(2026,3,29), datetime(2026,3,29)),
        "3d": (datetime(2026,3,27), datetime(2026,3,29)),
        "7d": (datetime(2026,3,23), datetime(2026,3,29)),
        "15d": (datetime(2026,3,15), datetime(2026,3,29)),
        "30d": (datetime(2026,2,28), datetime(2026,3,29)),
        "45d": (datetime(2026,2,12), datetime(2026,3,29)),
    }
    result = {}
    for pn, (start, end) in periods.items():
        s=r=p=pv=a=c=0
        for row in daily_rows:
            d = parse_date(row[0])
            if start <= d <= end:
                s+=row[1]; pv+=row[2]; a+=row[3]; c+=row[4]; p+=row[5]; r+=row[6]
        cvr = round(p/s*100,2) if s>0 else 0
        aov = round(r/p,2) if p>0 else 0
        result[pn] = {"sessions":s,"revenue":round(r,2),"purchases":p,"pdp_views":pv,"atc":a,"checkouts":c,"cvr":cvr,"aov":aov,"ad_spend":None,"roas":None,"cpa":None}
    return result

def make_daily(rows):
    return sorted([{"date":r[0][:10],"sessions":r[1],"pdp_views":r[2],"atc":r[3],"checkouts":r[4],"purchases":r[5],"revenue":r[6]} for r in rows], key=lambda x:x["date"])

