def main():
    print("Updating all brand data files...")
    for bid, bname in BRANDS.items():
        fp = os.path.join(DATA, f"{bid}.json")
        if os.path.exists(fp):
            with open(fp) as f:
                data = json.load(f)
        else:
            data = {"brand_id": bid, "brand_name": bname}
        data["brand_name"] = bname
        data["brand_id"] = bid
        data["last_updated"] = "2026-03-30T00:00:00Z"
        if bid in F and F[bid]:
            rows = F[bid]
            periods = aggregate_periods(rows)
            perf = data.get("performance", {})
            perf.update(periods)
            perf["daily"] = make_daily(rows)
            data["performance"] = perf
        elif bid not in F:
            z = {"sessions":0,"revenue":0,"purchases":0,"pdp_views":0,"atc":0,"checkouts":0,"cvr":0,"aov":0,"ad_spend":None,"roas":None,"cpa":None}
            data["performance"] = {"yesterday":z.copy(),"3d":z.copy(),"7d":z.copy(),"15d":z.copy(),"30d":z.copy(),"45d":z.copy(),"daily":[]}
        with open(fp, "w") as f:
            json.dump(data, f, indent=2, ensure_ascii=False)
        d7 = data.get("performance",{}).get("7d",{})
        print(f"  {bname}: 7d sessions={d7.get('sessions',0)}, rev=${d7.get('revenue',0):,.2f}, purchases={d7.get('purchases',0)}, cvr={d7.get('cvr',0)}%")
    print(f"\nDone. {len(BRANDS)} brands updated.")

if __name__ == "__main__":
    main()
